     1→/**
     2→ * Performance Tracking Utility
     3→ *
     4→ * Provides a standardized wrapper for tracking execution time and updating
     5→ * classification context across all pipeline stages. Eliminates duplicate
     6→ * timing capture code and ensures consistent performance metadata.
     7→ *
     8→ * @module utils/performance-tracking
     9→ */
    10→
    11→import { ClassificationContext } from '../stages/types';
    12→
    13→/**
    14→ * Tracks performance and updates context for a pipeline stage execution.
    15→ *
    16→ * This utility wraps stage execution logic to automatically:
    17→ * - Capture accurate timing (start to finish)
    18→ * - Update context.stageTimings with duration in milliseconds
    19→ * - Update context.configurationRefs with config path reference
    20→ * - Preserve exact return values and types from wrapped function
    21→ * - Handle both synchronous and asynchronous operations
    22→ * - Ensure context updates even if wrapped function throws
    23→ *
    24→ * @template T - Return type of the wrapped stage function
    25→ * @param stageName - Name of the stage (used as key in context.stageTimings and context.configurationRefs)
    26→ * @param configPath - Configuration path reference (e.g., 'category_signals.*.hard_assertions')
    27→ * @param context - Classification context to update with timing and config reference
    28→ * @param stageFunction - The stage logic to execute (sync or async)
    29→ * @returns The exact return value from stageFunction
    30→ * @throws Re-throws any errors from stageFunction after updating context
    31→ *
    32→ * @example
    33→ * // Synchronous stage
    34→ * const result = trackStagePerformance(
    35→ *   'hard_assertions',
    36→ *   'category_signals.*.hard_assertions',
    37→ *   context,
    38→ *   () => {
    39→ *     // Stage logic here
    40→ *     return { categoriesWithHardAssertions: ['FINANCE'] };
    41→ *   }
    42→ * );
    43→ *
    44→ * @example
    45→ * // Asynchronous stage
    46→ * const result = await trackStagePerformance(
    47→ *   'ai_routing',
    48→ *   'confidence_thresholds',
    49→ *   context,
    50→ *   async () => {
    51→ *     const response = await callOpenAI(...);
    52→ *     return { requiresAI: true };
    53→ *   }
    54→ * );
    55→ */
    56→export function trackStagePerformance<T>(
    57→  stageName: string,
    58→  configPath: string,
    59→  context: ClassificationContext,
    60→  stageFunction: () => T
    61→): T {
    62→  const startTime = Date.now();
    63→
    64→  try {
    65→    const result = stageFunction();
    66→
    67→    // Handle async functions
    68→    if (result instanceof Promise) {
    69→      return result
    70→        .then((asyncResult) => {
    71→          // Update context after async completion
    72→          const duration = Date.now() - startTime;
    73→          context.stageTimings[stageName] = duration;
    74→          context.configurationRefs[stageName] = configPath;
    75→          return asyncResult;
    76→        })
