     1→import { z } from 'zod';
     2→import { EmailMessage, RuleMatch } from '../types';
     3→import { extractTextFromHtml } from '../utils/email-utils';
     4→import { ClassificationContext } from './types';
     5→
     6→/**
     7→ * Rule-Based Scoring Stage
     8→ *
     9→ * Implements lexical pattern matching per SCORING_LOGIC.md "Subtype Scoring Formula" section.
    10→ * Applies rule-based classification patterns with bounded aggregation to prevent score inflation
    11→ * while allowing multiple patterns to contribute to category confidence.
    12→ *
    13→ * Logic:
    14→ * - score(subtype) = sum(top_k(high_matches, K_high))
    15→ *                  + M_medium * sum(top_k(medium_matches, K_medium))
    16→ *                  + M_low * sum(top_k(low_matches, K_low))
    17→ *                  + attribute_bonus(subtype)
    18→ * - Category score = primary + min(secondary_support, secondary_support_cap)
    19→ * - Uses max of existing score vs aggregated rule score
    20→ */
    21→
    22→export interface RulePattern {
    23→  field: string; // "subject", "body", "from.address", etc.
    24→  operation: string; // "contains_any", "starts_with", "ends_with", "regex_any", "exists"
    25→  values?: string[];
    26→  weight: number;
    27→}
    28→
    29→export interface SubtypeRuleClassification {
    30→  high_confidence?: RulePattern[];
    31→  medium_confidence?: RulePattern[];
    32→  low_confidence?: RulePattern[];
    33→}
    34→
    35→export interface SubtypeDefinition {
    36→  description: string;
    37→  rule_based_classification?: SubtypeRuleClassification;
    38→  derived?: boolean;
    39→  derivation_logic?: string;
    40→}
    41→
