   150→export function executeRuleScoring(
   151→  email: EmailMessage,
   152→  context: ClassificationContext,
   153→  config: RuleScoringStageConfig
   154→): RuleScoringResult {
   155→  const startTime = Date.now();
   156→
   157→  console.log(`Rule scoring for email ${email.id}: "${email.subject?.substring(0, 50)}..."`);
   158→
   159→  const { settings, topLevelCategories, tuningParameters } = config;
   160→
   161→  // Early exit if rule scoring is disabled
   162→  if (!settings.use_lexical_patterns || !settings.apply_subtype_rules) {
   163→    console.log('Rule scoring disabled by configuration');
   164→    return {
   165→      categoryResults: [],
   166→      updatedScores: { ...context.categoryScores },
   167→      totalMatches: 0,
   168→      categoriesWithRules: 0,
   169→      highestRuleScore: 0,
   170→      processingDurationMs: Date.now() - startTime,
   171→    };
   172→  }
   173→
   174→  const categoryResults: CategoryRuleResult[] = [];
   175→  const updatedScores = { ...context.categoryScores };
   176→
   177→  console.log(`Found ${Object.keys(topLevelCategories).length} top-level categories to process`);
   178→
   179→  // Process each top-level category
   180→  for (const [categoryCode, categoryData] of Object.entries(topLevelCategories)) {
   181→    console.log(
   182→      `Processing category '${categoryCode}' with ${Object.keys(categoryData.subtypes || {}).length} subtypes`
   183→    );
   184→
   185→    const subtypeScores: Record<string, SubtypeScore> = {};
   186→    const categoryRuleMatches: RuleScoringMatch[] = [];
   187→    const categoryRationale: string[] = [];
   188→
   189→    // Process subtypes for this category
   190→    if (categoryData.subtypes) {
   191→      for (const [subtypeCode, subtypeData] of Object.entries(categoryData.subtypes)) {
   192→        const subtypeScore = scoreSubtype(email, subtypeData, subtypeCode, tuningParameters);
   193→
   194→        if (subtypeScore.score > 0) {
   195→          subtypeScores[subtypeCode] = subtypeScore;
   196→          categoryRuleMatches.push(...subtypeScore.matches);
   197→          console.log(
   198→            `Subtype '${subtypeCode}' scored ${subtypeScore.score} with ${subtypeScore.matches.length} matches`
   199→          );
   200→        }
   201→      }
   202→    }
   203→
   204→    // Calculate aggregated category score using bounded aggregation
   205→    let categoryScore = context.categoryScores[categoryCode] || 0; // Start with existing score
   206→
   207→    if (settings.bounded_aggregation && Object.keys(subtypeScores).length > 0) {
   208→      const aggregatedScore = calculateBoundedAggregation(subtypeScores, tuningParameters);
   209→
   210→      // Use max of existing score vs aggregated rule score
   211→      categoryScore = Math.max(categoryScore, aggregatedScore.totalScore);
   212→
   213→      categoryRationale.push(`Rule aggregation: ${aggregatedScore.breakdown}`);
   214→      console.log(
   215→        `Category '${categoryCode}' rule score: ${aggregatedScore.totalScore} (${aggregatedScore.breakdown})`
   216→      );
   217→    }
   218→
   219→    // Calculate confidence based on score and number of matches
   220→    const confidence = calculateConfidence(categoryScore, categoryRuleMatches.length);
   221→
   222→    // Select best subtype
   223→    const selectedSubtypeId = selectBestSubtype(subtypeScores);
   224→
   225→    // Create category result
   226→    const categoryResult: CategoryRuleResult = {
   227→      categoryCode,
   228→      aggregatedScore: categoryScore,
   229→      subtypeScores,
   230→      ruleMatches: categoryRuleMatches,
   231→      scoringRationale:
   232→        categoryRationale.length > 0
   233→          ? categoryRationale
   234→          : [`Rule-based classification: ${categoryScore} points from ${categoryRuleMatches.length} matches`],
   235→      selectedSubtypeId,
   236→      confidence,
   237→    };
   238→
   239→    categoryResults.push(categoryResult);
   240→    updatedScores[categoryCode] = categoryScore;
   241→  }
   242→
   243→  // Calculate summary metrics
   244→  const totalMatches = categoryResults.reduce((sum, result) => sum + result.ruleMatches.length, 0);
   245→  const categoriesWithRules = categoryResults.filter((result) => Object.keys(result.subtypeScores).length > 0).length;
   246→  const highestRuleScore = Math.max(...Object.values(updatedScores), 0);
   247→
   248→  // Update context tracking
   249→  const processingDurationMs = Date.now() - startTime;
   250→  context.stageTimings['rule_scoring'] = processingDurationMs;
   251→  context.configurationRefs['rule_scoring'] =
   252→    'config.processing_config.top_level_categories.*.subtypes.*.rule_based_classification';
   253→
   254→  console.log(`Rule scoring complete - ${totalMatches} matches across ${categoriesWithRules} categories`);
   255→
   256→  return {
   257→    categoryResults,
