   266→/**
   267→ * Score a single subtype based on its rule-based classification patterns
   268→ */
   269→function scoreSubtype(
   270→  email: EmailMessage,
   271→  subtypeData: SubtypeDefinition,
   272→  subtypeCode: string,
   273→  tuningParams: RuleScoringStageConfig['tuningParameters']
   274→): SubtypeScore {
   275→  const subject = email.subject?.toLowerCase() || '';
   276→  const bodyText = email.bodyPlain
   277→    ? email.bodyPlain.toLowerCase()
   278→    : email.bodyHtml
   279→      ? extractTextFromHtml(email.bodyHtml).toLowerCase()
   280→      : '';
   281→
   282→  const ruleClassification = subtypeData.rule_based_classification || {};
   283→  const matches: RuleScoringMatch[] = [];
   284→
   285→  // Process each confidence tier with bounded aggregation
   286→  const confidenceTiers: Array<{
   287→    tier: keyof SubtypeRuleClassification;
   288→    multiplier: number;
   289→    maxMatches: number;
   290→  }> = [
   291→    { tier: 'high_confidence', multiplier: 1.0, maxMatches: tuningParams.K_high },
   292→    { tier: 'medium_confidence', multiplier: tuningParams.M_medium, maxMatches: tuningParams.K_medium },
   293→    { tier: 'low_confidence', multiplier: tuningParams.M_low, maxMatches: tuningParams.K_low },
   294→  ];
   295→
   296→  let totalScore = 0;
   297→
   298→  for (const { tier, multiplier, maxMatches } of confidenceTiers) {
   299→    const tierRules = ruleClassification[tier] || [];
   300→    const tierMatches: RuleScoringMatch[] = [];
   301→
   302→    for (const rule of tierRules) {
   303→      const match = evaluateRule(rule, subject, bodyText);
   304→
   305→      if (match.matched) {
   306→        tierMatches.push({
   307→          tier,
   308→          field: rule.field,
   309→          operation: rule.operation,
   310→          values: rule.values || [],
   311→          weight: rule.weight,
   312→          matchedValue: match.matchedValue,
   313→          ruleId: `${subtypeCode}_${tier}_${tierMatches.length}`,
   314→          ruleWeight: rule.weight, // For compatibility with RuleMatch base interface
   315→          partialMatch: false, // For compatibility with RuleMatch base interface
   316→        });
   317→
   318→        console.log(`Rule match - ${tier} in ${rule.field}: "${match.matchedValue}" (weight: ${rule.weight})`);
   319→      }
   320→    }
   321→
   322→    // Apply bounded aggregation - take top K matches for this tier
   323→    const topMatches = tierMatches.sort((a, b) => b.weight - a.weight).slice(0, maxMatches);
   324→
   325→    // Add to total score and matches
   326→    for (const match of topMatches) {
   327→      totalScore += match.weight * multiplier;
   328→      matches.push(match);
   329→    }
   330→  }
   331→
   332→  return {
   333→    score: totalScore,
   334→    matches,
   335→    breakdown: matches.length > 0 ? matches.map((m) => `${m.tier}:${m.weight}`).join(',') : 'no_matches',
   336→  };
   337→}
   338→
   339→/**
   340→ * Evaluate a single rule against email content
   341→ */
   342→function evaluateRule(rule: RulePattern, subject: string, body: string): { matched: boolean; matchedValue: string } {
   343→  let fieldValue = '';
   344→
   345→  switch (rule.field) {
   346→  case 'subject':
   347→    fieldValue = subject;
   348→    break;
   349→  case 'body':
   350→    fieldValue = body;
   351→    break;
   352→  case 'from.address':
   353→    // This would need access to email.from, but we'll handle it in a future iteration
   354→    fieldValue = '';
   355→    break;
   356→  default:
   357→    fieldValue = '';
   358→  }
   359→
   360→  if (!fieldValue) {
   361→    return { matched: false, matchedValue: '' };
   362→  }
   363→
   364→  const values = Array.isArray(rule.values) ? rule.values : rule.values ? [rule.values] : [];
   365→
   366→  switch (rule.operation) {
   367→  case 'contains_any':
   368→    for (const value of values) {
   369→      if (fieldValue.includes(value.toLowerCase())) {
   370→        return { matched: true, matchedValue: value };
   371→      }
   372→    }
   373→    break;
   374→
   375→  case 'starts_with':
   376→    for (const value of values) {
   377→      if (fieldValue.startsWith(value.toLowerCase())) {
   378→        return { matched: true, matchedValue: value };
   379→      }
   380→    }
   381→    break;
   382→
   383→  case 'ends_with':
   384→    for (const value of values) {
   385→      if (fieldValue.endsWith(value.toLowerCase())) {
   386→        return { matched: true, matchedValue: value };
   387→      }
   388→    }
   389→    break;
   390→
   391→  case 'regex_any':
   392→    for (const pattern of values) {
   393→      try {
   394→        const regex = new RegExp(pattern, 'i');
   395→        const match = regex.exec(fieldValue);
   396→        if (match) {
   397→          return { matched: true, matchedValue: match[0] };
   398→        }
   399→      } catch (e) {
   400→        console.log(`Invalid regex pattern "${pattern}": ${e}`);
   401→      }
   402→    }
   403→    break;
   404→
   405→  case 'exists':
   406→    return { matched: fieldValue.length > 0, matchedValue: fieldValue.substring(0, 50) };
   407→
   408→  default:
   409→    console.log(`Unknown rule operation: ${rule.operation}`);
   410→  }
   411→
   412→  return { matched: false, matchedValue: '' };
   413→}
   414→
   415→/**
   416→ * Calculate bounded aggregation score to prevent inflation
   417→ * Uses diminishing returns: primary subtype + dampened tail support
   418→ */
   419→function calculateBoundedAggregation(
   420→  subtypeScores: Record<string, SubtypeScore>,
   421→  tuningParams: RuleScoringStageConfig['tuningParameters']
   422→): { totalScore: number; breakdown: string } {
   423→  const scores = Object.entries(subtypeScores)
   424→    .map(([subtype, data]) => ({ subtype, score: data.score }))
   425→    .sort((a, b) => b.score - a.score); // Sort by score descending
   426→
   427→  if (scores.length === 0) {
   428→    return { totalScore: 0, breakdown: 'no_subtypes' };
   429→  }
   430→
   431→  // Primary subtype (highest score) contributes fully
   432→  const primaryScore = scores[0].score;
   433→  const primarySubtype = scores[0].subtype;
   434→
   435→  // Tail support: additional subtypes contribute with diminishing returns
   436→  let tailSupport = 0;
   437→  const tailContributions: string[] = [];
   438→
   439→  if (scores.length > 1) {
   440→    const tailScores = scores.slice(1);
   441→
   442→    for (const tail of tailScores) {
   443→      const contribution = tail.score * tuningParams.TAIL_DAMPEN;
   444→      tailSupport += contribution;
   445→      tailContributions.push(`${tail.subtype}:${contribution.toFixed(1)}`);
   446→    }
   447→
   448→    // Apply tail ratio cap
   449→    const maxTailSupport = primaryScore * tuningParams.TAIL_RATIO_CAP;
   450→    tailSupport = Math.min(tailSupport, maxTailSupport);
   451→  }
   452→
   453→  const totalScore = primaryScore + tailSupport;
   454→  const breakdown =
   455→    `primary:${primarySubtype}:${primaryScore}` +
   456→    (tailSupport > 0 ? ` + tail:${tailSupport.toFixed(1)}(${tailContributions.join(',')})` : '');
   457→
   458→  return { totalScore, breakdown };
   459→}
   460→
   461→/**
   462→ * Calculate confidence percentage based on score and number of matches
   463→ */
   464→function calculateConfidence(score: number, numMatches: number): number {
   465→  if (score === 0) return 0;
   466→
   467→  // Basic confidence calculation: higher scores and more matches = higher confidence
   468→  // Cap at 95% to leave room for AI enhancement
   469→  const baseConfidence = Math.min(score * 5, 80); // 5% per point, max 80%
   470→  const matchBonus = Math.min(numMatches * 3, 15); // 3% per match, max 15%
   471→
   472→  return Math.min(baseConfidence + matchBonus, 95);
   473→}
   474→
   475→/**
   476→ * Select the best subtype based on scores
   477→ */
   478→function selectBestSubtype(subtypeScores: Record<string, SubtypeScore>): string | null {
   479→  if (!subtypeScores || Object.keys(subtypeScores).length === 0) {
   480→    return null;
   481→  }
   482→
   483→  // Find subtype with highest score
   484→  let bestSubtype: string | null = null;
   485→  let bestScore = -1;
   486→
   487→  for (const [subtypeId, scoreData] of Object.entries(subtypeScores)) {
   488→    const score = scoreData?.score || 0;
   489→    if (score > bestScore) {
   490→      bestScore = score;
   491→      bestSubtype = subtypeId;
   492→    }
   493→  }
   494→
   495→  return bestScore > 0 ? bestSubtype : null;
   496→}
