    71→}
    72→
    73→/**
    74→ * Execute disambiguation stage
    75→ *
    76→ * Analyzes candidate scores to identify competing categories and applies
    77→ * targeted adjustments using DISAMBIGUATOR attributes to resolve conflicts.
    78→ */
    79→export async function executeDisambiguation(
    80→  email: EmailMessage,
    81→  context: AttributeContext,
    82→  config: CategoryConfiguration
    83→): Promise<DisambiguationResult> {
    84→  const startTime = Date.now();
    85→
    86→  // Validate configuration
    87→  if (!config.processing_config?.settings?.disambiguation) {
    88→    throw new Error('Disambiguation configuration not found');
    89→  }
    90→
    91→  const disambiguationConfig = config.processing_config.settings.disambiguation;
    92→  validateDisambiguationConfig(disambiguationConfig);
    93→
    94→  // Extract candidate scores from email
    95→  const emailData = email as EmailMessage & Record<string, unknown>;
    96→  const candidateScores = (emailData.candidate_scores as Record<string, number>) || {};
    97→
    98→  const originalScores = { ...candidateScores };
    99→  const updatedScores = { ...candidateScores };
   100→
   101→  // If no scores or insufficient scores, skip disambiguation
   102→  if (Object.keys(candidateScores).length < 2) {
   103→    return createEmptyResult(originalScores, updatedScores, disambiguationConfig, startTime, emailData);
