   126→  }
   127→
   128→  const processingDuration = Math.max(1, Date.now() - startTime);
   129→
   130→  // Build result
   131→  const result: DisambiguationResult = {
   132→    competing_categories: competingCategories,
   133→    adjustments_applied: adjustmentsApplied,
   134→    original_scores: originalScores,
   135→    updated_scores: updatedScores,
   136→    score_deltas: scoreDeltas,
   137→    processing_duration_ms: processingDuration,
   138→    configuration_references: {
   139→      disambiguation_settings_path: 'processing_config.settings.disambiguation',
   140→      confidence_gap_threshold: disambiguationConfig.confidence_gap_threshold,
   141→    },
   142→  };
   143→
   144→  // Preserve stage chain data
   145→  if ('candidate_scores' in emailData) {
   146→    result.candidate_scores = updatedScores; // Update with new scores
   147→  }
   148→  if ('stage_results' in emailData && emailData.stage_results) {
   149→    result.stage_results = {
   150→      ...(emailData.stage_results as Record<string, unknown>),
