   154→
   155→  return result;
   156→}
   157→
   158→/**
   159→ * Identify competing categories that require disambiguation
   160→ */
   161→function identifyCompetingCategories(
   162→  candidateScores: Record<string, number>,
   163→  config: DisambiguationConfig
   164→): CompetingCategoryPair[] {
   165→  const competingPairs: CompetingCategoryPair[] = [];
   166→  const categories = Object.entries(candidateScores).sort(([, a], [, b]) => b - a); // Sort by score descending
   167→
   168→  // Check all pairs for competition
   169→  for (let i = 0; i < categories.length; i++) {
   170→    for (let j = i + 1; j < categories.length; j++) {
   171→      const [category1, score1] = categories[i];
   172→      const [category2, score2] = categories[j];
   173→
   174→      const scoreGap = Math.abs(score1 - score2);
   175→
   176→      if (scoreGap <= config.confidence_gap_threshold) {
   177→        const isSubtypeCompetition = areSubtypesOfSameCategory(category1, category2);
   178→
   179→        // Skip subtype competition if disabled
   180→        if (
   181→          isSubtypeCompetition &&
   182→          !(config.enable_subtype_disambiguation ?? DISAMBIGUATION_DEFAULTS.ENABLE_SUBTYPE_DISAMBIGUATION)
   183→        ) {
   184→          continue;
   185→        }
   186→
   187→        competingPairs.push({
   188→          category1,
   189→          category2,
   190→          score_gap: scoreGap,
   191→          requires_disambiguation: true,
   192→          subtype_competition: isSubtypeCompetition,
   193→        });
   194→      }
   195→    }
   196→  }
   197→
   198→  return competingPairs;
   199→}
   200→
   201→/**
   202→ * Calculate disambiguation adjustments using DISAMBIGUATOR attributes
   203→ */
   204→function calculateDisambiguationAdjustments(
   205→  competingCategories: CompetingCategoryPair[],
   206→  context: AttributeContext,
   207→  config: CategoryConfiguration,
   208→  disambiguationConfig: DisambiguationConfig
   209→): DisambiguationAdjustment[] {
   210→  const adjustments: DisambiguationAdjustment[] = [];
   211→  const categoryAdjustmentCounts: Record<string, number> = {};
   212→
   213→  // Get all categories involved in competition
   214→  const involvedCategories = new Set<string>();
   215→  for (const pair of competingCategories) {
   216→    involvedCategories.add(pair.category1);
   217→    involvedCategories.add(pair.category2);
   218→  }
   219→
   220→  // Find DISAMBIGUATOR attributes for involved categories
   221→  for (const [attributeName, metadata] of Object.entries(context.detectionMetadata)) {
   222→    for (const categoryName of Array.from(involvedCategories)) {
   223→      const categoryKey = getCategoryKey(categoryName);
   224→      const subtypeKey = getSubtypeKey(categoryName);
   225→
   226→      const attributeRole = getAttributeRole(attributeName, categoryKey, subtypeKey, config);
   227→
   228→      if (attributeRole === 'DISAMBIGUATOR') {
   229→        // Check if we've hit the adjustment limit
   230→        if (
   231→          adjustments.length >=
   232→          (disambiguationConfig.max_adjustments_per_email || DISAMBIGUATION_DEFAULTS.MAX_ADJUSTMENTS_PER_EMAIL)
   233→        ) {
   234→          break;
   235→        }
   236→
   237→        // Calculate adjustment amount
   238→        const categoryAdjustmentCount = categoryAdjustmentCounts[categoryName] || 0;
   239→        const decayFactor = Math.pow(
   240→          disambiguationConfig.adjustment_decay_factor || DISAMBIGUATION_DEFAULTS.ADJUSTMENT_DECAY_FACTOR,
   241→          categoryAdjustmentCount
   242→        );
   243→
   244→        // Base adjustment proportional to confidence
   245→        const baseAdjustment = 0.1 * metadata.confidence; // 10% max adjustment scaled by confidence
   246→        const adjustmentAmount = baseAdjustment * decayFactor;
   247→
   248→        adjustments.push({
