     1→/**
     2→ * Multi-Label Selection Stage
     3→ *
     4→ * Implements sophisticated multi-label selection logic based on ranking algorithms,
     5→ * confidence thresholds, co-presence rules, and AI routing decisions.
     6→ *
     7→ * This stage is responsible for:
     8→ * - Ranking categories by final scores
     9→ * - Selecting primary and secondary labels based on confidence and gap thresholds
    10→ * - Enforcing co-presence rules and allowed combinations
    11→ * - Determining AI classification requirements
    12→ * - Generating complete selection rationale and audit trails
    13→ */
    14→
    15→import {
    16→  CategoryScore,
    17→  MultiLabelConfig,
    18→  ConfidenceThresholds,
    19→  SelectedLabel,
    20→  SelectionSummary,
    21→  MultiLabelSelectionResult,
    22→} from './types';
    23→
    24→export class MultiLabelSelectionStage {
    25→  private config: MultiLabelConfig;
    26→  private thresholds: ConfidenceThresholds;
    27→
    28→  constructor(config: MultiLabelConfig, thresholds: ConfidenceThresholds) {
    29→    this.validateConfiguration(config, thresholds);
    30→    this.config = config;
    31→    this.thresholds = thresholds;
    32→  }
    33→
    34→  /**
    35→   * Validate configuration parameters
    36→   */
    37→  private validateConfiguration(config: MultiLabelConfig, thresholds: ConfidenceThresholds): void {
    38→    if (config.maxLabels < 0) {
    39→      throw new Error('Invalid configuration: maxLabels cannot be negative');
    40→    }
    41→
    42→    if (config.minSecondaryConfidence < 0) {
    43→      throw new Error('Invalid configuration: minSecondaryConfidence cannot be negative');
    44→    }
    45→
    46→    if (thresholds.highConfidence <= thresholds.mediumConfidence) {
    47→      throw new Error('Invalid threshold configuration: highConfidence must be greater than mediumConfidence');
    48→    }
    49→
    50→    if (thresholds.mediumConfidence <= thresholds.lowConfidence) {
    51→      throw new Error('Invalid threshold configuration: mediumConfidence must be greater than lowConfidence');
    52→    }
    53→
    54→    if (thresholds.secondaryLabelMinGap < 0) {
    55→      throw new Error('Invalid threshold configuration: secondaryLabelMinGap cannot be negative');
    56→    }
    57→  }
    58→
    59→  /**
    60→   * Rank categories by score in descending order, filtering out zero/negative scores
    61→   */
    62→  public rankCategoriesByScore(candidateScores: Record<string, CategoryScore>): Array<{
    63→    category: string;
    64→    score: number;
    65→    confidence: number;
    66→    rationale: string;
    67→    selectedSubtypeId?: string | null;
    68→  }> {
    69→    return Object.entries(candidateScores)
    70→      .map(([category, scoreData]) => ({
    71→        category,
    72→        score: scoreData.score || 0,
    73→        confidence: scoreData.confidence || 0,
    74→        rationale: scoreData.rationale || '',
    75→        selectedSubtypeId: scoreData.selectedSubtypeId,
    76→      }))
    77→      .filter((item) => item.score > 0)
    78→      .sort((a, b) => {
    79→        // Primary sort by score (descending)
    80→        if (b.score !== a.score) {
    81→          return b.score - a.score;
    82→        }
    83→        // Secondary sort by category name for stable ordering
    84→        return a.category.localeCompare(b.category);
    85→      });
    86→  }
    87→
    88→  /**
    89→   * Main selection logic: select labels based on multi-label selection rules
    90→   */
    91→  public selectLabels(candidateScores: Record<string, CategoryScore>): MultiLabelSelectionResult {
    92→    const startTime = Date.now();
    93→
    94→    // Rank categories by score
    95→    const rankedCategories = this.rankCategoriesByScore(candidateScores);
    96→
    97→    if (rankedCategories.length === 0) {
    98→      return this.createNoSelectionResult(startTime);
    99→    }
   100→
   101→    const selectedLabels: SelectedLabel[] = [];
   102→
   103→    // Select primary label
   104→    const primaryCandidate = rankedCategories[0];
   105→    if (primaryCandidate.score >= this.thresholds.lowConfidence) {
   106→      const primaryLabel: SelectedLabel = {
   107→        category: primaryCandidate.category,
   108→        subtype: primaryCandidate.selectedSubtypeId || null,
   109→        confidence: primaryCandidate.confidence,
   110→        score: primaryCandidate.score,
   111→        isPrimary: true,
   112→        labelOrder: 1,
   113→        selectionRationale: `Primary label: highest score (${primaryCandidate.score}) above minimum threshold (${this.thresholds.lowConfidence})`,
   114→      };
   115→      selectedLabels.push(primaryLabel);
   116→    } else {
   117→      return this.createNoSelectionResult(startTime);
   118→    }
   119→
   120→    // Select secondary labels
   121→    this.selectSecondaryLabels(rankedCategories, selectedLabels, primaryCandidate);
   122→
   123→    // Update category decisions
   124→    this.updateCategoryDecisions(candidateScores, selectedLabels);
   125→
   126→    // Determine AI classification need
   127→    const needsAiClassification = this.determineAiClassificationNeed(selectedLabels);
   128→
   129→    // Create selection summary
   130→    const selectionSummary = this.createSelectionSummary(selectedLabels, rankedCategories, needsAiClassification);
   131→
   132→    return {
   133→      selectedLabels,
   134→      needsAiClassification,
   135→      selectionSummary,
   136→      processingDurationMs: Date.now() - startTime,
   137→    };
   138→  }
   139→
   140→  /**
   141→   * Select secondary labels within gap threshold and above minimum confidence
   142→   */
   143→  private selectSecondaryLabels(
   144→    rankedCategories: Array<{
   145→      category: string;
   146→      score: number;
   147→      confidence: number;
   148→      rationale: string;
   149→      selectedSubtypeId?: string | null;
   150→    }>,
   151→    selectedLabels: SelectedLabel[],
   152→    primaryCandidate: {
   153→      category: string;
   154→      score: number;
   155→      confidence: number;
   156→      rationale: string;
   157→      selectedSubtypeId?: string | null;
   158→    }
   159→  ): void {
   160→    if (this.config.maxLabels <= 1 || rankedCategories.length <= 1) {
   161→      return;
   162→    }
   163→
   164→    const primaryScore = primaryCandidate.score;
   165→
   166→    for (let i = 1; i < rankedCategories.length && selectedLabels.length < this.config.maxLabels; i++) {
   167→      const candidate = rankedCategories[i];
   168→      const scoreDifference = primaryScore - candidate.score;
   169→
   170→      // Check if candidate meets secondary label criteria
   171→      if (
   172→        candidate.score >= this.config.minSecondaryConfidence &&
   173→        scoreDifference <= this.thresholds.secondaryLabelMinGap
   174→      ) {
   175→        // Check if combination is allowed
   176→        if (this.isCombinationAllowed(primaryCandidate.category, candidate.category)) {
   177→          const secondaryLabel: SelectedLabel = {
   178→            category: candidate.category,
   179→            subtype: candidate.selectedSubtypeId || null,
   180→            confidence: candidate.confidence,
   181→            score: candidate.score,
   182→            isPrimary: false,
   183→            labelOrder: selectedLabels.length + 1,
   184→            selectionRationale: `Secondary label: score (${candidate.score}) within gap (${scoreDifference} <= ${this.thresholds.secondaryLabelMinGap}) and above minimum confidence (${this.config.minSecondaryConfidence})`,
   185→          };
   186→          selectedLabels.push(secondaryLabel);
   187→        }
   188→      }
   189→    }
   190→  }
   191→
   192→  /**
   193→   * Check if category combination is allowed based on configuration
   194→   */
   195→  private isCombinationAllowed(primaryCategory: string, candidateCategory: string): boolean {
   196→    if (primaryCategory === candidateCategory) {
   197→      return true;
   198→    }
   199→
   200→    // If strict mode is enabled and combinations are specified, only allow explicit combinations
   201→    if (this.config.strictCombinationMode && this.config.allowedCombinations.length > 0) {
   202→      const combination1 = `${primaryCategory}+${candidateCategory}`;
   203→      const combination2 = `${candidateCategory}+${primaryCategory}`;
   204→      return (
   205→        this.config.allowedCombinations.includes(combination1) || this.config.allowedCombinations.includes(combination2)
   206→      );
   207→    }
   208→
   209→    // If no combinations specified, allow all (default permissive mode)
   210→    if (this.config.allowedCombinations.length === 0) {
   211→      return true;
   212→    }
   213→
   214→    // If combinations are specified but not in strict mode, still check them (current config has financial+actionable)
   215→    const combination1 = `${primaryCategory}+${candidateCategory}`;
   216→    const combination2 = `${candidateCategory}+${primaryCategory}`;
   217→    const isExplicitlyAllowed =
   218→      this.config.allowedCombinations.includes(combination1) || this.config.allowedCombinations.includes(combination2);
   219→
   220→    // Allow explicitly configured combinations, and by default allow others too (unless strict mode)
   221→    return isExplicitlyAllowed || !this.config.strictCombinationMode;
   222→  }
   223→
   224→  /**
