   102→
   103→  // Validate inputs
   104→  validateInputs(email, session, classification, config);
   105→
   106→  // Extract routing thresholds with fallbacks
   107→  const highConfidenceThreshold =
   108→    config.settings.ai_routing.high_confidence_threshold || config.confidenceThresholds.highConfidence || 15;
   109→
   110→  const aiRequiredThreshold = config.confidenceThresholds.mediumConfidence || 8;
   111→
   112→  const lowConfidenceThreshold = config.confidenceThresholds.lowConfidence || 3;
   113→
   114→  const skipAiConditions = config.settings.ai_routing.skip_ai_conditions || [];
   115→
   116→  // Make routing decision
   117→  const routingDecision = makeRoutingDecision(
   118→    classification.selectedLabels,
   119→    classification.candidateScores,
   120→    highConfidenceThreshold,
   121→    aiRequiredThreshold,
   122→    lowConfidenceThreshold,
   123→    skipAiConditions
   124→  );
   125→
   126→  // Generate explainability trace
   127→  const explainabilityTrace = generateExplainabilityTrace(
   128→    classification,
   129→    routingDecision,
   130→    {
   131→      high_confidence_threshold: highConfidenceThreshold,
   132→      ai_required_threshold:
   133→        config.settings.ai_routing.ai_required_threshold || config.confidenceThresholds.aiClassificationRequired || 12,
   134→      low_confidence_threshold: lowConfidenceThreshold,
   135→    },
   136→    startTime
   137→  );
   138→
   139→  return {
   140→    routing_decision: routingDecision,
   141→    routing_branch: routingDecision.route_to_ai ? 'ai_classification' : 'direct_to_merge',
   142→    explainability_trace: explainabilityTrace,
   143→  };
   144→}
   145→
   146→/**
   147→ * Validate input parameters
   148→ */
   149→function validateInputs(
   150→  email: EmailMessage,
   151→  session: ClassificationSession,
