   185→      route_to_ai: true,
   186→      routing_reason: 'No labels selected - AI classification may recover classification',
   187→      confidence_assessment: 'no_classification',
   188→      cost_consideration: 'recovery_attempt',
   189→    };
   190→  }
   191→
   192→  // Case 2: Check for hard assertions (skip AI condition)
