   196→      return {
   197→        route_to_ai: false,
   198→        routing_reason: 'hard assertion applied - domain-based classification is authoritative',
   199→        confidence_assessment: 'hard_assertion_skip',
   200→        cost_consideration: 'ai_unnecessary',
   201→      };
   202→    }
   203→  }
   204→
   205→  // Case 3: Check primary label confidence
   206→  const primaryLabel = selectedLabels.find((label) => label.isPrimary) || selectedLabels[0];
