   211→    return {
   212→      route_to_ai: false,
   213→      routing_reason: `High confidence primary label ${primaryLabel.category} (score: ${primaryScore}) - rule-based results reliable`,
   214→      confidence_assessment: 'high_confidence',
   215→      cost_consideration: 'ai_unnecessary',
   216→    };
   217→  }
   218→
   219→  // Very low confidence - skip AI (likely unclassifiable)
   220→  if (primaryScore < lowConfidenceThreshold) {
   221→    return {
   222→      route_to_ai: false,
   223→      routing_reason: `Very low confidence primary label ${primaryLabel.category} (score: ${primaryScore}) - likely unclassifiable`,
   224→      confidence_assessment: 'very_low_confidence',
   225→      cost_consideration: 'ai_ineffective',
   226→    };
   227→  }
   228→
   229→  // Medium confidence range - analyze further for AI routing decision
   230→  const hasMultipleLabels = selectedLabels.length > 1;
   231→  const hasCloseCompetitors = checkCloseCompetitors(candidateScores, primaryScore, 3);
   232→
