    50→// Semantic intent extracted by AI
    51→export interface SemanticIntent {
    52→  primary_purpose: 'notification' | 'request' | 'update' | 'alert';
    53→  action_required: 'none' | 'view' | 'respond' | 'complete';
    54→  urgency_level: 'none' | 'low' | 'medium' | 'high';
    55→}
    56→
    57→// Evidence structure for category enhancements
    58→export interface CategoryEvidence {
    59→  quoted_phrases: string[];
    60→  keywords: string[];
    61→  reasoning: string;
    62→}
    63→
    64→// Category enhancement from AI analysis
    65→export interface CategoryEnhancement {
    66→  applies: boolean;
    67→  confidence_boost: number;
    68→  evidence: CategoryEvidence;
    69→}
    70→
    71→// Complete feature extraction result from AI
    72→export interface FeatureExtractionData {
    73→  semantic_intent: SemanticIntent;
    74→  category_enhancements: Record<string, CategoryEnhancement>;
    75→}
    76→
    77→// Evidence validation result
    78→export interface EvidenceValidation {
    79→  validPhrases: string[];
    80→  invalidPhrases: string[];
