    82→}
    83→
    84→// Complete stage result interface
    85→export interface FeatureExtractionResult {
    86→  featureExtraction: FeatureExtractionData;
    87→  validationPassed: boolean;
    88→  validationErrors: string[];
    89→  evidenceValidation: EvidenceValidation;
    90→  processingDurationMs: number;
    91→  tokenUsage: number;
    92→  apiCallCount: number;
    93→  retryCount: number;
    94→}
    95→
    96→/**
    97→ * AI Feature Extraction Stage Implementation
    98→ *
    99→ * Integrates with OpenAI GPT-4o-mini to extract semantic features and enhance
   100→ * category classifications with evidence-grounded analysis.
   101→ */
   102→export async function aiFeatureExtractionStage(
   103→  email: EmailMessage,
   104→  session: ClassificationSession,
   105→  candidateCategories: Record<string, unknown>,
   106→  detectedAttributes: Record<string, unknown>,
   107→  config: AIFeatureExtractionConfig
   108→): Promise<FeatureExtractionResult> {
   109→  const startTime = Date.now();
   110→  let retryCount = 0;
   111→  let apiCallCount = 0;
   112→
   113→  // Validate inputs
   114→  validateInputs(email, session, config);
   115→
   116→  // Initialize OpenAI client
   117→  const openai = new OpenAI({
   118→    apiKey: config.openai.apiKey,
   119→  });
   120→
   121→  // Setup JSON schema validator (only used for legacy json_object mode)
   122→  const ajv = new Ajv();
   123→  const validateSchema = ajv.compile(config.featureExtractionSchema.schema);
   124→
   125→  // Retry loop for API calls
   126→  let lastError: Error | null = null;
   127→
   128→  while (retryCount < config.retryPolicy.maxRetries) {
   129→    try {
   130→      apiCallCount++;
   131→
   132→      // Prepare prompts with email content interpolation
   133→      const systemPrompt = config.prompts.systemPrompt.join('\n');
