   135→        config.prompts.userPrompt,
   136→        email,
   137→        candidateCategories,
   138→        detectedAttributes
   139→      );
   140→
   141→      // Prepare response format based on configuration
   142→      const responseFormat =
   143→        config.openai.responseFormat === 'json_schema'
   144→          ? {
   145→            type: 'json_schema' as const,
   146→            json_schema: {
   147→              name: config.featureExtractionSchema.name || 'feature_extraction',
   148→              description:
   149→                  config.featureExtractionSchema.description ||
   150→                  'Extract semantic features and category enhancements from email content',
   151→              schema: config.featureExtractionSchema.schema,
   152→              strict: config.featureExtractionSchema.strict ?? true,
   153→            },
   154→          }
   155→          : { type: 'json_object' as const }; // Backward compatibility
   156→
   157→      // Call OpenAI API with structured outputs
   158→      const response = await openai.chat.completions.create({
   159→        model: config.openai.model,
   160→        temperature: config.openai.temperature,
   161→        response_format: responseFormat,
   162→        messages: [
   163→          { role: 'system', content: systemPrompt },
   164→          { role: 'user', content: userPrompt },
   165→        ],
   166→      });
   167→
   168→      // Parse and validate response
   169→      const rawContent = response.choices[0].message.content;
   170→      if (!rawContent) {
   171→        throw new Error('Empty response from OpenAI');
   172→      }
   173→
   174→      let featureExtractionData: FeatureExtractionData;
   175→      try {
   176→        featureExtractionData = JSON.parse(rawContent);
   177→      } catch {
   178→        throw new Error('Invalid JSON response from OpenAI');
   179→      }
   180→
   181→      // Schema validation: For structured outputs, OpenAI enforces the schema.
   182→      // For backward compatibility with json_object mode, we still validate with AJV.
   183→      const validationErrors: string[] = [];
   184→      let validationPassed = true;
   185→
   186→      if (config.openai.responseFormat === 'json_object') {
   187→        // Only validate with AJV for legacy json_object mode
   188→        validationPassed = validateSchema(featureExtractionData);
   189→
   190→        if (!validationPassed && validateSchema.errors) {
   191→          for (const error of validateSchema.errors) {
   192→            validationErrors.push(`${error.instancePath} ${error.message}`);
   193→          }
   194→          throw new Error('Schema validation failed: ' + validationErrors.join(', '));
   195→        }
   196→      }
   197→      // For json_schema mode, OpenAI has already enforced the schema, so no additional validation needed
   198→
   199→      // Validate evidence grounding
   200→      const evidenceValidation = validateEvidenceGrounding(email, featureExtractionData);
   201→
   202→      // Success - return result
   203→      return {
   204→        featureExtraction: featureExtractionData,
   205→        validationPassed: true,
   206→        validationErrors: [],
   207→        evidenceValidation,
   208→        processingDurationMs: Date.now() - startTime,
   209→        tokenUsage: response.usage?.total_tokens || 0,
   210→        apiCallCount,
   211→        retryCount,
   212→      };
   213→    } catch (error) {
   214→      lastError = error as Error;
   215→      retryCount++;
   216→
   217→      if (retryCount < config.retryPolicy.maxRetries) {
   218→        // Wait before retry with exponential backoff
   219→        await new Promise((resolve) => setTimeout(resolve, config.retryPolicy.backoffMs * Math.pow(2, retryCount - 1)));
   220→      }
   221→    }
   222→  }
   223→
   224→  // All retries exhausted
   225→  throw new Error(`AI feature extraction failed after ${config.retryPolicy.maxRetries} retries: ${lastError?.message}`);
   226→}
   227→
   228→/**
   229→ * Validate input parameters
   230→ */
   231→function validateInputs(email: EmailMessage, session: ClassificationSession, config: AIFeatureExtractionConfig): void {
   232→  if (!email?.id && !('gmail_id' in email)) {
   233→    throw new Error('Invalid email input: id or gmail_id is required');
   234→  }
   235→
   236→  // Allow missing subjects but log a warning - production emails might legitimately have empty subjects
   237→  if (!email.subject) {
   238→    console.warn(`Email ${email.id} has missing subject, proceeding with empty subject for classification`);
   239→  }
   240→
   241→  if (!session?.id && !('session_id' in session)) {
   242→    throw new Error('Invalid session input: id or session_id is required');
   243→  }
   244→
   245→  if (!config) {
   246→    throw new Error('Configuration is required');
   247→  }
   248→
   249→  if (!config.openai?.apiKey || config.openai.apiKey.trim() === '') {
   250→    throw new Error('Invalid configuration: OpenAI API key is required');
   251→  }
   252→
   253→  if (!config.prompts?.systemPrompt || !config.prompts?.userPrompt) {
   254→    throw new Error('Invalid configuration: system and user prompts are required');
   255→  }
   256→
   257→  if (!config.featureExtractionSchema) {
   258→    throw new Error('Invalid configuration: feature extraction schema is required');
   259→  }
   260→}
   261→
   262→/**
   263→ * Interpolate user prompt template with email content and analysis data
   264→ *
   265→ * Supports dynamic object path resolution with these placeholders:
   266→ * - {email.from} - formatted email address
   267→ * - {email.subject} - email subject
