export function executeStrongIndicators(
  email: EmailMessage,
  context: ClassificationContext,
  config: StrongIndicatorStageConfig
): StrongIndicatorsResult {
  const startTime = Date.now();
  const categoriesWithStrongIndicators: string[] = [];
  const indicatorResults: StrongIndicatorResult[] = [];
  const updatedSeeds: Record<string, number> = { ...context.strongIndicatorSeeds };

  const baseWeight = config.strongIndicatorBaseWeight;
  const diminishingFactor = config.diminishingReturnsFactor;

  // Process each category that has strong indicators configured
  for (const [categoryName, categoryConfig] of Object.entries(config.categorySignals)) {
    if (!categoryConfig.strong_indicators) {
      continue;
    }

    const strongIndicators = categoryConfig.strong_indicators;
    const existingSeed = updatedSeeds[categoryName] || 0;
    let categoryHadIndicator = false;
    let newSeedScore = existingSeed;

    // Track matches per dimension for diminishing returns
    const dimensionMatches = {
      from_domain: 0,
      subject_contains: 0,
      body_contains: 0,
    };

    // Check from_domains_ref (domain-based strong indicators)
    if (strongIndicators.from_domains_ref) {
      const { source_group, confidence } = strongIndicators.from_domains_ref;

      const domainGroup = config.domainLookup[source_group];
      if (domainGroup) {
        const emailDomain = extractDomainFromEmail(email.from.email);
        const matchedDomain = findMatchingDomain(emailDomain, domainGroup, confidence);

        if (matchedDomain) {
          dimensionMatches.from_domain++;
          const isFirstMatch = dimensionMatches.from_domain === 1;
          const effectiveWeight = isFirstMatch ? baseWeight : baseWeight * diminishingFactor;
          const proposedSeed = newSeedScore + effectiveWeight;

          indicatorResults.push({
            category: categoryName,
            indicatorType: 'from_domain',
            matchedValue: matchedDomain.domain,
            seedScore: effectiveWeight,
            diminishingReturnsApplied: !isFirstMatch,
            existingSeedScore: newSeedScore,
            finalSeedScore: proposedSeed,
            reason: `Email from domain '${emailDomain}' matches ${confidence}-confidence domain '${matchedDomain.domain}' in group '${source_group}'. Weight: ${effectiveWeight} (${isFirstMatch ? 'full' : 'diminished'})`,
          });

          newSeedScore = Math.max(newSeedScore, proposedSeed);
          categoryHadIndicator = true;
        }
      }
    }

    // Check subject_contains
    if (strongIndicators.subject_contains && email.subject) {
      const matchedKeywords = findMatchingKeywords(email.subject, strongIndicators.subject_contains);

      for (const keyword of matchedKeywords) {
        dimensionMatches.subject_contains++;
        const isFirstMatch = dimensionMatches.subject_contains === 1;
        const effectiveWeight = isFirstMatch ? baseWeight : baseWeight * diminishingFactor;
        const proposedSeed = newSeedScore + effectiveWeight;

        indicatorResults.push({
          category: categoryName,
          indicatorType: 'subject_contains',
          matchedValue: keyword,
          seedScore: effectiveWeight,
          diminishingReturnsApplied: !isFirstMatch,
          existingSeedScore: newSeedScore,
          finalSeedScore: proposedSeed,
          reason: `Subject '${email.subject}' contains strong indicator keyword '${keyword}'. Weight: ${effectiveWeight} (${isFirstMatch ? 'full' : 'diminished'})`,
        });

        newSeedScore = Math.max(newSeedScore, proposedSeed);
        categoryHadIndicator = true;
      }
    }

    // Check body_contains
    if (strongIndicators.body_contains && (email.bodyPlain || email.bodyHtml)) {
      // Use plain text body if available, otherwise extract from HTML
      const bodyText = email.bodyPlain || extractTextFromHtml(email.bodyHtml || '');
      const matchedKeywords = findMatchingKeywords(bodyText, strongIndicators.body_contains);

      for (const keyword of matchedKeywords) {
        dimensionMatches.body_contains++;
        const isFirstMatch = dimensionMatches.body_contains === 1;
        const effectiveWeight = isFirstMatch ? baseWeight : baseWeight * diminishingFactor;
        const proposedSeed = newSeedScore + effectiveWeight;

        indicatorResults.push({
          category: categoryName,
          indicatorType: 'body_contains',
          matchedValue: keyword,
          seedScore: effectiveWeight,
          diminishingReturnsApplied: !isFirstMatch,
          existingSeedScore: newSeedScore,
          finalSeedScore: proposedSeed,
          reason: `Body text contains strong indicator keyword '${keyword}'. Weight: ${effectiveWeight} (${isFirstMatch ? 'full' : 'diminished'})`,
        });

        newSeedScore = Math.max(newSeedScore, proposedSeed);
        categoryHadIndicator = true;
      }
    }

    // Update seed score using max logic (strong_indicator_seed = max(existing_seed, seed))
    if (categoryHadIndicator) {
      updatedSeeds[categoryName] = newSeedScore;
      categoriesWithStrongIndicators.push(categoryName);
    }
  }

  const processingDurationMs = Date.now() - startTime;

  // Update context tracking
  context.stageTimings['strong_indicators'] = processingDurationMs;
  context.configurationRefs['strong_indicators'] = 'category_signals.*.strong_indicators';
  context.strongIndicatorSeeds = updatedSeeds;

  return {
    categoriesWithStrongIndicators,
    indicatorResults,
    updatedSeeds,
    processingDurationMs,
  };
}

