describe('context tracking and performance', () => {
  it('should track processing duration and update context', () => {
    const email = createMockEmail();
    const context = createMockContext();

    const result = executeHardAssertions(email, context, mockConfig);

    expect(result.processingDurationMs).toBeGreaterThanOrEqual(0);
    expect(context.stageTimings.hard_assertions).toBe(result.processingDurationMs);
    expect(context.configurationRefs.hard_assertions).toBe('category_signals.*.hard_assertions');
  });

  it('should handle empty configuration gracefully', () => {
    const email = createMockEmail();
    const context = createMockContext();
