/**
 * Performance Tracking Utility
 *
 * Provides a standardized wrapper for tracking execution time and updating
 * classification context across all pipeline stages. Eliminates duplicate
 * timing capture code and ensures consistent performance metadata.
 *
 * @module utils/performance-tracking
 */

import { ClassificationContext } from '../stages/types';

/**
 * Tracks performance and updates context for a pipeline stage execution.
 *
 * This utility wraps stage execution logic to automatically:
 * - Capture accurate timing (start to finish)
 * - Update context.stageTimings with duration in milliseconds
 * - Update context.configurationRefs with config path reference
 * - Preserve exact return values and types from wrapped function
 * - Handle both synchronous and asynchronous operations
 * - Ensure context updates even if wrapped function throws
 *
 * @template T - Return type of the wrapped stage function
 * @param stageName - Name of the stage (used as key in context.stageTimings and context.configurationRefs)
 * @param configPath - Configuration path reference (e.g., 'category_signals.*.hard_assertions')
 * @param context - Classification context to update with timing and config reference
 * @param stageFunction - The stage logic to execute (sync or async)
 * @returns The exact return value from stageFunction
 * @throws Re-throws any errors from stageFunction after updating context
 *
 * @example
 * // Synchronous stage
 * const result = trackStagePerformance(
 *   'hard_assertions',
 *   'category_signals.*.hard_assertions',
 *   context,
 *   () => {
 *     // Stage logic here
 *     return { categoriesWithHardAssertions: ['FINANCE'] };
 *   }
 * );
 *
 * @example
 * // Asynchronous stage
 * const result = await trackStagePerformance(
 *   'ai_routing',
 *   'confidence_thresholds',
 *   context,
 *   async () => {
 *     const response = await callOpenAI(...);
 *     return { requiresAI: true };
 *   }
 * );
 */
export function trackStagePerformance<T>(
  stageName: string,
  configPath: string,
  context: ClassificationContext,
  stageFunction: () => T
): T {
  const startTime = Date.now();

  try {
    const result = stageFunction();

    // Handle async functions
    if (result instanceof Promise) {
      return result
        .then((asyncResult) => {
          // Update context after async completion
          const duration = Date.now() - startTime;
          context.stageTimings[stageName] = duration;
          context.configurationRefs[stageName] = configPath;
          return asyncResult;
        })
        .catch((error) => {
          // Update context even on error
          const duration = Date.now() - startTime;
          context.stageTimings[stageName] = duration;
          context.configurationRefs[stageName] = configPath;
          throw error;
        }) as T;
    }

    // Update context for sync functions
    const duration = Date.now() - startTime;
    context.stageTimings[stageName] = duration;
    context.configurationRefs[stageName] = configPath;

    return result;
  } catch (error) {
    // Update context even on sync error
    const duration = Date.now() - startTime;
    context.stageTimings[stageName] = duration;
    context.configurationRefs[stageName] = configPath;
    throw error;
  }
}

