     1→import { z } from 'zod';
     2→import { EmailMessage, RuleMatch } from '../types';
     3→import { extractTextFromHtml } from '../utils/email-utils';
     4→import { ClassificationContext } from './types';
     5→import { trackStagePerformance } from '../utils/performance-tracking';
     6→
     7→/**
     8→ * Rule-Based Scoring Stage
     9→ *
    10→ * Implements lexical pattern matching per SCORING_LOGIC.md "Subtype Scoring Formula" section.
    11→ * Applies rule-based classification patterns with bounded aggregation to prevent score inflation
    12→ * while allowing multiple patterns to contribute to category confidence.
    13→ *
    14→ * Logic:
    15→ * - score(subtype) = sum(top_k(high_matches, K_high))
    16→ *                  + M_medium * sum(top_k(medium_matches, K_medium))
    17→ *                  + M_low * sum(top_k(low_matches, K_low))
    18→ *                  + attribute_bonus(subtype)
    19→ * - Category score = primary + min(secondary_support, secondary_support_cap)
    20→ * - Uses max of existing score vs aggregated rule score
    21→ */
    22→
    23→export interface RulePattern {
    24→  field: string; // "subject", "body", "from.address", etc.
    25→  operation: string; // "contains_any", "starts_with", "ends_with", "regex_any", "exists"
    26→  values?: string[];
    27→  weight: number;
    28→}
    29→
    30→export interface SubtypeRuleClassification {
    31→  high_confidence?: RulePattern[];
    32→  medium_confidence?: RulePattern[];
    33→  low_confidence?: RulePattern[];
    34→}
    35→
    36→export interface SubtypeDefinition {
    37→  description: string;
    38→  rule_based_classification?: SubtypeRuleClassification;
    39→  derived?: boolean;
    40→  derivation_logic?: string;
    41→}
    42→
    43→export interface TopLevelCategory {
    44→  description: string;
    45→  subtypes: Record<string, SubtypeDefinition>;
    46→}
    47→
    48→export interface RuleScoringStageConfig {
    49→  // Configuration settings for rule scoring behavior
    50→  settings: {
    51→    use_lexical_patterns: boolean;
    52→    apply_subtype_rules: boolean;
    53→    bounded_aggregation: boolean;
    54→  };
    55→
    56→  // Top-level categories with their subtypes and rules
    57→  topLevelCategories: Record<string, TopLevelCategory>;
    58→
    59→  // Tuning parameters for subtype scoring formula
    60→  tuningParameters: {
    61→    K_high: number; // Max high-confidence matches to consider
    62→    K_medium: number; // Max medium-confidence matches to consider
    63→    K_low: number; // Max low-confidence matches to consider
    64→    M_medium: number; // Multiplier for medium-confidence scores
    65→    M_low: number; // Multiplier for low-confidence scores
    66→    TAIL_DAMPEN: number; // Damping factor for secondary subtype support
    67→    TAIL_RATIO_CAP: number; // Max ratio of tail support to primary score
    68→  };
    69→}
    70→
    71→// Using RuleMatch from explainability-trace.ts types
    72→export interface RuleScoringMatch extends RuleMatch {
    73→  tier: 'high_confidence' | 'medium_confidence' | 'low_confidence';
    74→  values: string[];
    75→  weight: number;
    76→  ruleId: string;
    77→}
    78→
    79→export interface SubtypeScore {
    80→  score: number;
    81→  matches: RuleScoringMatch[];
    82→  breakdown: string;
    83→}
    84→
    85→export interface CategoryRuleResult {
    86→  categoryCode: string;
    87→  aggregatedScore: number;
    88→  subtypeScores: Record<string, SubtypeScore>;
    89→  ruleMatches: RuleScoringMatch[];
