   268→/**
   269→ * Score a single subtype based on its rule-based classification patterns
   270→ */
   271→function scoreSubtype(
   272→  email: EmailMessage,
   273→  subtypeData: SubtypeDefinition,
   274→  subtypeCode: string,
   275→  tuningParams: RuleScoringStageConfig['tuningParameters']
   276→): SubtypeScore {
   277→  const subject = email.subject?.toLowerCase() || '';
   278→  const bodyText = email.bodyPlain
   279→    ? email.bodyPlain.toLowerCase()
   280→    : email.bodyHtml
   281→      ? extractTextFromHtml(email.bodyHtml).toLowerCase()
   282→      : '';
   283→
   284→  const ruleClassification = subtypeData.rule_based_classification || {};
   285→  const matches: RuleScoringMatch[] = [];
   286→
   287→  // Process each confidence tier with bounded aggregation
   288→  const confidenceTiers: Array<{
   289→    tier: keyof SubtypeRuleClassification;
   290→    multiplier: number;
   291→    maxMatches: number;
   292→  }> = [
   293→    { tier: 'high_confidence', multiplier: 1.0, maxMatches: tuningParams.K_high },
   294→    { tier: 'medium_confidence', multiplier: tuningParams.M_medium, maxMatches: tuningParams.K_medium },
   295→    { tier: 'low_confidence', multiplier: tuningParams.M_low, maxMatches: tuningParams.K_low },
   296→  ];
   297→
   298→  let totalScore = 0;
   299→
   300→  for (const { tier, multiplier, maxMatches } of confidenceTiers) {
   301→    const tierRules = ruleClassification[tier] || [];
   302→    const tierMatches: RuleScoringMatch[] = [];
   303→
   304→    for (const rule of tierRules) {
   305→      const match = evaluateRule(rule, subject, bodyText);
   306→
   307→      if (match.matched) {
   308→        tierMatches.push({
   309→          tier,
   310→          field: rule.field,
   311→          operation: rule.operation,
   312→          values: rule.values || [],
   313→          weight: rule.weight,
   314→          matchedValue: match.matchedValue,
   315→          ruleId: `${subtypeCode}_${tier}_${tierMatches.length}`,
   316→          ruleWeight: rule.weight, // For compatibility with RuleMatch base interface
   317→          partialMatch: false, // For compatibility with RuleMatch base interface
   318→        });
   319→
   320→        console.log(`Rule match - ${tier} in ${rule.field}: "${match.matchedValue}" (weight: ${rule.weight})`);
   321→      }
   322→    }
   323→
   324→    // Apply bounded aggregation - take top K matches for this tier
   325→    const topMatches = tierMatches.sort((a, b) => b.weight - a.weight).slice(0, maxMatches);
   326→
   327→    // Add to total score and matches
   328→    for (const match of topMatches) {
   329→      totalScore += match.weight * multiplier;
   330→      matches.push(match);
   331→    }
   332→  }
   333→
   334→  return {
   335→    score: totalScore,
   336→    matches,
   337→    breakdown: matches.length > 0 ? matches.map((m) => `${m.tier}:${m.weight}`).join(',') : 'no_matches',
   338→  };
   339→}
   340→
   341→/**
   342→ * Evaluate a single rule against email content
   343→ */
   344→function evaluateRule(rule: RulePattern, subject: string, body: string): { matched: boolean; matchedValue: string } {
   345→  let fieldValue = '';
   346→
   347→  switch (rule.field) {
   348→  case 'subject':
   349→    fieldValue = subject;
   350→    break;
   351→  case 'body':
   352→    fieldValue = body;
   353→    break;
   354→  case 'from.address':
   355→    // This would need access to email.from, but we'll handle it in a future iteration
   356→    fieldValue = '';
   357→    break;
   358→  default:
   359→    fieldValue = '';
   360→  }
   361→
   362→  if (!fieldValue) {
   363→    return { matched: false, matchedValue: '' };
   364→  }
   365→
   366→  const values = Array.isArray(rule.values) ? rule.values : rule.values ? [rule.values] : [];
   367→
   368→  switch (rule.operation) {
   369→  case 'contains_any':
   370→    for (const value of values) {
   371→      if (fieldValue.includes(value.toLowerCase())) {
   372→        return { matched: true, matchedValue: value };
   373→      }
   374→    }
   375→    break;
   376→
   377→  case 'starts_with':
   378→    for (const value of values) {
   379→      if (fieldValue.startsWith(value.toLowerCase())) {
   380→        return { matched: true, matchedValue: value };
   381→      }
   382→    }
   383→    break;
   384→
   385→  case 'ends_with':
   386→    for (const value of values) {
   387→      if (fieldValue.endsWith(value.toLowerCase())) {
   388→        return { matched: true, matchedValue: value };
   389→      }
   390→    }
   391→    break;
   392→
   393→  case 'regex_any':
   394→    for (const pattern of values) {
   395→      try {
   396→        const regex = new RegExp(pattern, 'i');
   397→        const match = regex.exec(fieldValue);
   398→        if (match) {
   399→          return { matched: true, matchedValue: match[0] };
   400→        }
   401→      } catch (e) {
   402→        console.log(`Invalid regex pattern "${pattern}": ${e}`);
   403→      }
   404→    }
   405→    break;
   406→
   407→  case 'exists':
   408→    return { matched: fieldValue.length > 0, matchedValue: fieldValue.substring(0, 50) };
   409→
   410→  default:
   411→    console.log(`Unknown rule operation: ${rule.operation}`);
   412→  }
   413→
   414→  return { matched: false, matchedValue: '' };
   415→}
   416→
   417→/**
   418→ * Calculate bounded aggregation score to prevent inflation
   419→ * Uses diminishing returns: primary subtype + dampened tail support
   420→ */
   421→function calculateBoundedAggregation(
   422→  subtypeScores: Record<string, SubtypeScore>,
   423→  tuningParams: RuleScoringStageConfig['tuningParameters']
   424→): { totalScore: number; breakdown: string } {
   425→  const scores = Object.entries(subtypeScores)
   426→    .map(([subtype, data]) => ({ subtype, score: data.score }))
   427→    .sort((a, b) => b.score - a.score); // Sort by score descending
   428→
   429→  if (scores.length === 0) {
   430→    return { totalScore: 0, breakdown: 'no_subtypes' };
   431→  }
   432→
   433→  // Primary subtype (highest score) contributes fully
   434→  const primaryScore = scores[0].score;
   435→  const primarySubtype = scores[0].subtype;
   436→
   437→  // Tail support: additional subtypes contribute with diminishing returns
   438→  let tailSupport = 0;
   439→  const tailContributions: string[] = [];
   440→
   441→  if (scores.length > 1) {
   442→    const tailScores = scores.slice(1);
   443→
   444→    for (const tail of tailScores) {
   445→      const contribution = tail.score * tuningParams.TAIL_DAMPEN;
   446→      tailSupport += contribution;
   447→      tailContributions.push(`${tail.subtype}:${contribution.toFixed(1)}`);
   448→    }
   449→
   450→    // Apply tail ratio cap
   451→    const maxTailSupport = primaryScore * tuningParams.TAIL_RATIO_CAP;
   452→    tailSupport = Math.min(tailSupport, maxTailSupport);
   453→  }
   454→
   455→  const totalScore = primaryScore + tailSupport;
   456→  const breakdown =
   457→    `primary:${primarySubtype}:${primaryScore}` +
   458→    (tailSupport > 0 ? ` + tail:${tailSupport.toFixed(1)}(${tailContributions.join(',')})` : '');
   459→
   460→  return { totalScore, breakdown };
   461→}
   462→
   463→/**
   464→ * Calculate confidence percentage based on score and number of matches
   465→ */
   466→function calculateConfidence(score: number, numMatches: number): number {
   467→  if (score === 0) return 0;
   468→
   469→  // Basic confidence calculation: higher scores and more matches = higher confidence
   470→  // Cap at 95% to leave room for AI enhancement
   471→  const baseConfidence = Math.min(score * 5, 80); // 5% per point, max 80%
   472→  const matchBonus = Math.min(numMatches * 3, 15); // 3% per match, max 15%
   473→
   474→  return Math.min(baseConfidence + matchBonus, 95);
   475→}
   476→
   477→/**
   478→ * Select the best subtype based on scores
   479→ */
   480→function selectBestSubtype(subtypeScores: Record<string, SubtypeScore>): string | null {
   481→  if (!subtypeScores || Object.keys(subtypeScores).length === 0) {
   482→    return null;
   483→  }
   484→
   485→  // Find subtype with highest score
   486→  let bestSubtype: string | null = null;
   487→  let bestScore = -1;
   488→
   489→  for (const [subtypeId, scoreData] of Object.entries(subtypeScores)) {
   490→    const score = scoreData?.score || 0;
   491→    if (score > bestScore) {
   492→      bestScore = score;
   493→      bestSubtype = subtypeId;
   494→    }
   495→  }
   496→
   497→  return bestScore > 0 ? bestSubtype : null;
   498→}
