     1→/**
     2→ * Attribute Detection Stage
     3→ *
     4→ * Stage 4 of the EmailCategorizer pipeline. Detects and derives contextual attributes
     5→ * from email content and metadata that will influence category scoring in the next stage.
     6→ *
     7→ * Implements pattern-based and derived attribute detection per SCORING_LOGIC.md
     8→ * "Attribute Detectors & Derived Attributes" section.
     9→ */
    10→
    11→import { EmailMessage, ProcessingConfig, AttributeDetector, DerivedAttribute } from '../types';
    12→import { ClassificationContext } from './types';
    13→import { trackStagePerformance } from '../utils/performance-tracking';
    14→import { extractEmailBodyText } from '../utils/email-utils';
    15→
    16→/**
    17→ * Individual detected attribute result
    18→ */
    19→export interface DetectedAttribute {
    20→  attribute_name: string;
    21→  attribute_value: boolean | string | number;
    22→  detection_method: 'pattern' | 'derived' | 'domain_lookup';
    23→  detection_evidence: string;
    24→  confidence: number;
    25→}
    26→
    27→/**
    28→ * Result of attribute detection stage
    29→ */
    30→export interface AttributeDetectionResult {
    31→  detected_attributes: DetectedAttribute[];
    32→  processing_duration_ms: number;
    33→  parallel_processed: boolean;
    34→  dependencies: string[];
    35→  // Preserve previous stage data
    36→  [key: string]: unknown;
    37→}
    38→
    39→/**
    40→ * Attribute Detection Stage Configuration
    41→ */
    42→export interface AttributeDetectionStageConfig {
    43→  settings: {
    44→    attribute_processing: {
    45→      detect_self_sent: boolean;
    46→      resolve_domains: boolean;
    47→      derive_context_flags: boolean;
    48→    };
    49→  };
    50→  attributes: {
    51→    schema: Record<string, unknown>;
    52→    detectors: AttributeDetector[];
    53→    derived: Record<string, DerivedAttribute>;
    54→    attribute_bonus_map?: Record<string, Record<string, number>>;
    55→  };
    56→  performance_cache?: {
    57→    financial_domains?: string[];
    58→    newsletter_domains?: string[];
    59→    logistics_domains?: string[];
    60→  };
    61→}
    62→
    63→/**
    64→ * Execute attribute detection stage function
    65→ */
    66→export function executeAttributeDetection(
    67→  email: EmailMessage,
    68→  context: ClassificationContext,
    69→  config: AttributeDetectionStageConfig
    70→): AttributeDetectionResult {
    71→  return trackStagePerformance('attribute_detection', 'attributes.detectors', context, () => {
    72→    const detectedAttributes: DetectedAttribute[] = [];
    73→
    74→    // Apply pattern-based detectors
    75→    const patternAttributes = detectPatternAttributes(email, config);
    76→    detectedAttributes.push(...patternAttributes);
    77→
    78→    // Apply derived attribute logic
    79→    const derivedAttributes = detectDerivedAttributes(email, config);
    80→    detectedAttributes.push(...derivedAttributes);
    81→
    82→    return {
    83→      detected_attributes: detectedAttributes,
    84→      processing_duration_ms: Math.max(1, context.stageTimings['attribute_detection'] || 0),
    85→      parallel_processed: true,
    86→      dependencies: [],
    87→    };
    88→  });
    89→}
    90→
    91→/**
    92→ * Detect pattern-based attributes using configured detectors
    93→ */
    94→function detectPatternAttributes(email: EmailMessage, config: AttributeDetectionStageConfig): DetectedAttribute[] {
    95→  const detectors = config.attributes?.detectors || [];
    96→  const detectedAttributes: DetectedAttribute[] = [];
    97→
    98→  for (const detector of detectors) {
    99→    try {
   100→      const detection = applyDetector(email, detector);
   101→      if (detection.detected) {
   102→        detectedAttributes.push({
   103→          attribute_name: detector.attribute,
   104→          attribute_value: detection.value as string | number | boolean,
   105→          detection_method: 'pattern',
   106→          detection_evidence: detection.evidence || 'Pattern match',
   107→          confidence: 0.8, // Default confidence for pattern matches
   108→        });
   109→      }
   110→    } catch (error) {
   111→      // Log error but continue processing
   112→      console.warn(`Error applying detector for ${detector.attribute}:`, error);
   113→    }
   114→  }
   115→
   116→  return detectedAttributes;
   117→}
   118→
   119→/**
   120→ * Apply individual detector pattern to email content
   121→ */
   122→function applyDetector(
   123→  email: EmailMessage,
   124→  detector: AttributeDetector
   125→): { detected: boolean; value?: unknown; evidence?: string } {
   126→  const { field, operation, values } = detector;
   127→
   128→  // Get the field content to search
   129→  let searchContent = '';
   130→  switch (field) {
   131→  case 'body':
   132→    searchContent = extractEmailBodyText(email);
   133→    break;
   134→  case 'subject':
   135→    searchContent = email.subject || '';
   136→    break;
   137→  case 'from.address':
   138→    searchContent = email.from?.email || '';
   139→    break;
   140→  case 'from.name':
   141→    searchContent = email.from?.name || '';
   142→    break;
   143→  default:
   144→    console.warn(`Unknown field type for detector: ${field}`);
   145→    return { detected: false };
   146→  }
   147→
   148→  // Apply detection operation
   149→  switch (operation) {
   150→  case 'contains_any':
   151→    for (const value of values) {
   152→      if (searchContent.toLowerCase().includes(value.toLowerCase())) {
   153→        return {
   154→          detected: true,
   155→          value: true,
   156→          evidence: `Found "${value}" in ${field}`,
   157→        };
   158→      }
   159→    }
   160→    break;
   161→
   162→  case 'regex_any':
   163→    for (const pattern of values) {
   164→      try {
   165→        const regex = new RegExp(pattern, 'ig'); // Add global flag for better matching
   166→        const match = searchContent.match(regex);
   167→        if (match) {
   168→          // For amount patterns, try to match the longest currency pattern
   169→          let bestMatch = match[0];
   170→          if (pattern.includes('\\$\\d+')) {
   171→            // Special handling for currency amounts - match full amounts with decimals
   172→            const fullAmountRegex = /\$\d+(?:\.\d{2})?/g;
   173→            const fullMatches = searchContent.match(fullAmountRegex);
   174→            if (fullMatches && fullMatches.length > 0) {
   175→              bestMatch = fullMatches[0]; // Use the first full amount match
   176→            }
   177→          }
   178→          return {
   179→            detected: true,
   180→            value: true,
   181→            evidence: `Regex "${pattern}" matched: "${bestMatch}" in ${field}`,
   182→          };
   183→        }
   184→      } catch (error) {
   185→        console.warn(`Invalid regex pattern: ${pattern}`, error);
   186→        continue;
   187→      }
   188→    }
   189→    break;
   190→
   191→  case 'starts_with':
   192→    for (const value of values) {
   193→      if (searchContent.toLowerCase().startsWith(value.toLowerCase())) {
   194→        return {
   195→          detected: true,
   196→          value: true,
   197→          evidence: `${field} starts with "${value}"`,
   198→        };
   199→      }
   200→    }
   201→    break;
   202→
   203→  case 'ends_with':
   204→    for (const value of values) {
   205→      if (searchContent.toLowerCase().endsWith(value.toLowerCase())) {
   206→        return {
   207→          detected: true,
   208→          value: true,
   209→          evidence: `${field} ends with "${value}"`,
   210→        };
   211→      }
   212→    }
   213→    break;
   214→
   215→  default:
   216→    console.warn(`Unknown operation type: ${operation}`);
   217→  }
   218→
   219→  return { detected: false };
   220→}
   221→
   222→/**
   223→ * Detect derived attributes using logical rules
   224→ */
   225→function detectDerivedAttributes(email: EmailMessage, config: AttributeDetectionStageConfig): DetectedAttribute[] {
   226→  const settings = config.settings?.attribute_processing;
   227→  const detectedAttributes: DetectedAttribute[] = [];
   228→
   229→  // Derive self_sent attribute (if enabled, default true)
   230→  const detectSelfSent = !settings || settings.detect_self_sent !== false;
   231→  if (detectSelfSent) {
   232→    const selfSent = deriveSelfSent(email);
   233→    if (selfSent) {
   234→      detectedAttributes.push(selfSent);
   235→    }
   236→  }
   237→
   238→  // Domain-based derivations (if enabled, default true)
   239→  const resolveDomains = !settings || settings.resolve_domains !== false;
   240→  if (resolveDomains) {
   241→    // Derive from_financial_institution attribute
   242→    const financialInstitution = deriveFromFinancialInstitution(email, config);
   243→    if (financialInstitution) {
   244→      detectedAttributes.push(financialInstitution);
   245→    }
   246→
   247→    // Derive from_newsletter_source attribute
   248→    const newsletterSource = deriveFromNewsletterSource(email, config);
   249→    if (newsletterSource) {
   250→      detectedAttributes.push(newsletterSource);
   251→    }
   252→
   253→    // Derive from_logistics_carrier attribute
   254→    const logisticsCarrier = deriveFromLogisticsCarrier(email, config);
   255→    if (logisticsCarrier) {
   256→      detectedAttributes.push(logisticsCarrier);
   257→    }
   258→  }
   259→
   260→  return detectedAttributes;
   261→}
   262→
   263→/**
   264→ * Derive self_sent attribute - email sent from user to self
   265→ */
   266→function deriveSelfSent(email: EmailMessage): DetectedAttribute | null {
   267→  const userAddresses = getUserAddresses();
   268→  const fromAddress = email.from?.email?.toLowerCase();
   269→
   270→  // Check if from address is user address
   271→  if (!fromAddress || !userAddresses.includes(fromAddress)) {
   272→    return null;
   273→  }
   274→
   275→  // Check if all recipients are user addresses
   276→  const allRecipients: string[] = [];
   277→  if (email.to) {
   278→    allRecipients.push(...email.to.map((addr) => addr.email.toLowerCase()));
   279→  }
   280→  if (email.cc) {
   281→    allRecipients.push(...email.cc.map((addr) => addr.email.toLowerCase()));
   282→  }
   283→  if (email.bcc) {
   284→    allRecipients.push(...email.bcc.map((addr) => addr.email.toLowerCase()));
   285→  }
   286→
   287→  const allRecipientsAreUser = allRecipients.length > 0 && allRecipients.every((addr) => userAddresses.includes(addr));
   288→
   289→  // Check for List-Id header (exclude mailing lists)
   290→  const hasListId = email.payload?.headers?.some((header) => header.name.toLowerCase() === 'list-id');
