   268→/**
   269→ * Score a single subtype based on its rule-based classification patterns
   270→ */
   271→function scoreSubtype(
   272→  email: EmailMessage,
   273→  subtypeData: SubtypeDefinition,
   274→  subtypeCode: string,
   275→  tuningParams: RuleScoringStageConfig['tuningParameters']
   276→): SubtypeScore {
   277→  const subject = email.subject?.toLowerCase() || '';
   278→  const bodyText = extractEmailBodyText(email).toLowerCase();
   279→
   280→  const ruleClassification = subtypeData.rule_based_classification || {};
   281→  const matches: RuleScoringMatch[] = [];
   282→
   283→  // Process each confidence tier with bounded aggregation
   284→  const confidenceTiers: Array<{
   285→    tier: keyof SubtypeRuleClassification;
   286→    multiplier: number;
   287→    maxMatches: number;
   288→  }> = [
   289→    { tier: 'high_confidence', multiplier: 1.0, maxMatches: tuningParams.K_high },
   290→    { tier: 'medium_confidence', multiplier: tuningParams.M_medium, maxMatches: tuningParams.K_medium },
   291→    { tier: 'low_confidence', multiplier: tuningParams.M_low, maxMatches: tuningParams.K_low },
   292→  ];
   293→
   294→  let totalScore = 0;
   295→
   296→  for (const { tier, multiplier, maxMatches } of confidenceTiers) {
   297→    const tierRules = ruleClassification[tier] || [];
   298→    const tierMatches: RuleScoringMatch[] = [];
   299→
   300→    for (const rule of tierRules) {
   301→      const match = evaluateRule(rule, subject, bodyText);
   302→
   303→      if (match.matched) {
   304→        tierMatches.push({
   305→          tier,
   306→          field: rule.field,
   307→          operation: rule.operation,
   308→          values: rule.values || [],
   309→          weight: rule.weight,
   310→          matchedValue: match.matchedValue,
   311→          ruleId: `${subtypeCode}_${tier}_${tierMatches.length}`,
   312→          ruleWeight: rule.weight, // For compatibility with RuleMatch base interface
   313→          partialMatch: false, // For compatibility with RuleMatch base interface
   314→        });
   315→
   316→        console.log(`Rule match - ${tier} in ${rule.field}: "${match.matchedValue}" (weight: ${rule.weight})`);
   317→      }
   318→    }
   319→
   320→    // Apply bounded aggregation - take top K matches for this tier
   321→    const topMatches = tierMatches.sort((a, b) => b.weight - a.weight).slice(0, maxMatches);
   322→
   323→    // Add to total score and matches
   324→    for (const match of topMatches) {
   325→      totalScore += match.weight * multiplier;
   326→      matches.push(match);
   327→    }
   328→  }
   329→
   330→  return {
   331→    score: totalScore,
   332→    matches,
   333→    breakdown: matches.length > 0 ? matches.map((m) => `${m.tier}:${m.weight}`).join(',') : 'no_matches',
   334→  };
   335→}
   336→
   337→/**
   338→ * Evaluate a single rule against email content
   339→ */
   340→function evaluateRule(rule: RulePattern, subject: string, body: string): { matched: boolean; matchedValue: string } {
   341→  let fieldValue = '';
   342→
   343→  switch (rule.field) {
   344→  case 'subject':
   345→    fieldValue = subject;
   346→    break;
   347→  case 'body':
   348→    fieldValue = body;
   349→    break;
   350→  case 'from.address':
   351→    // This would need access to email.from, but we'll handle it in a future iteration
   352→    fieldValue = '';
   353→    break;
   354→  default:
   355→    fieldValue = '';
   356→  }
   357→
   358→  if (!fieldValue) {
   359→    return { matched: false, matchedValue: '' };
   360→  }
   361→
   362→  const values = Array.isArray(rule.values) ? rule.values : rule.values ? [rule.values] : [];
   363→
   364→  switch (rule.operation) {
   365→  case 'contains_any':
   366→    for (const value of values) {
   367→      if (fieldValue.includes(value.toLowerCase())) {
   368→        return { matched: true, matchedValue: value };
   369→      }
   370→    }
   371→    break;
   372→
   373→  case 'starts_with':
   374→    for (const value of values) {
   375→      if (fieldValue.startsWith(value.toLowerCase())) {
   376→        return { matched: true, matchedValue: value };
   377→      }
   378→    }
   379→    break;
   380→
   381→  case 'ends_with':
   382→    for (const value of values) {
   383→      if (fieldValue.endsWith(value.toLowerCase())) {
   384→        return { matched: true, matchedValue: value };
   385→      }
   386→    }
   387→    break;
   388→
   389→  case 'regex_any':
   390→    for (const pattern of values) {
   391→      try {
   392→        const regex = new RegExp(pattern, 'i');
   393→        const match = regex.exec(fieldValue);
   394→        if (match) {
   395→          return { matched: true, matchedValue: match[0] };
   396→        }
   397→      } catch (e) {
   398→        console.log(`Invalid regex pattern "${pattern}": ${e}`);
   399→      }
   400→    }
   401→    break;
   402→
   403→  case 'exists':
   404→    return { matched: fieldValue.length > 0, matchedValue: fieldValue.substring(0, 50) };
   405→
   406→  default:
   407→    console.log(`Unknown rule operation: ${rule.operation}`);
   408→  }
   409→
   410→  return { matched: false, matchedValue: '' };
   411→}
   412→
   413→/**
   414→ * Calculate bounded aggregation score to prevent inflation
   415→ * Uses diminishing returns: primary subtype + dampened tail support
   416→ */
   417→function calculateBoundedAggregation(
   418→  subtypeScores: Record<string, SubtypeScore>,
   419→  tuningParams: RuleScoringStageConfig['tuningParameters']
   420→): { totalScore: number; breakdown: string } {
   421→  const scores = Object.entries(subtypeScores)
   422→    .map(([subtype, data]) => ({ subtype, score: data.score }))
   423→    .sort((a, b) => b.score - a.score); // Sort by score descending
   424→
   425→  if (scores.length === 0) {
   426→    return { totalScore: 0, breakdown: 'no_subtypes' };
   427→  }
   428→
   429→  // Primary subtype (highest score) contributes fully
   430→  const primaryScore = scores[0].score;
   431→  const primarySubtype = scores[0].subtype;
   432→
   433→  // Tail support: additional subtypes contribute with diminishing returns
   434→  let tailSupport = 0;
   435→  const tailContributions: string[] = [];
   436→
   437→  if (scores.length > 1) {
   438→    const tailScores = scores.slice(1);
   439→
   440→    for (const tail of tailScores) {
   441→      const contribution = tail.score * tuningParams.TAIL_DAMPEN;
   442→      tailSupport += contribution;
   443→      tailContributions.push(`${tail.subtype}:${contribution.toFixed(1)}`);
   444→    }
   445→
   446→    // Apply tail ratio cap
   447→    const maxTailSupport = primaryScore * tuningParams.TAIL_RATIO_CAP;
   448→    tailSupport = Math.min(tailSupport, maxTailSupport);
   449→  }
   450→
   451→  const totalScore = primaryScore + tailSupport;
   452→  const breakdown =
   453→    `primary:${primarySubtype}:${primaryScore}` +
   454→    (tailSupport > 0 ? ` + tail:${tailSupport.toFixed(1)}(${tailContributions.join(',')})` : '');
   455→
   456→  return { totalScore, breakdown };
   457→}
   458→
   459→/**
   460→ * Calculate confidence percentage based on score and number of matches
   461→ */
   462→function calculateConfidence(score: number, numMatches: number): number {
   463→  if (score === 0) return 0;
   464→
   465→  // Basic confidence calculation: higher scores and more matches = higher confidence
   466→  // Cap at 95% to leave room for AI enhancement
   467→  const baseConfidence = Math.min(score * 5, 80); // 5% per point, max 80%
   468→  const matchBonus = Math.min(numMatches * 3, 15); // 3% per match, max 15%
   469→
   470→  return Math.min(baseConfidence + matchBonus, 95);
   471→}
   472→
   473→/**
   474→ * Select the best subtype based on scores
   475→ */
   476→function selectBestSubtype(subtypeScores: Record<string, SubtypeScore>): string | null {
   477→  if (!subtypeScores || Object.keys(subtypeScores).length === 0) {
   478→    return null;
   479→  }
   480→
   481→  // Find subtype with highest score
   482→  let bestSubtype: string | null = null;
   483→  let bestScore = -1;
   484→
   485→  for (const [subtypeId, scoreData] of Object.entries(subtypeScores)) {
   486→    const score = scoreData?.score || 0;
   487→    if (score > bestScore) {
   488→      bestScore = score;
   489→      bestSubtype = subtypeId;
   490→    }
   491→  }
   492→
   493→  return bestScore > 0 ? bestSubtype : null;
   494→}
