/**
 * Category Utilities
 *
 * Utility functions for parsing and working with category and subtype names
 * in the classification pipeline. Category names follow the pattern:
 * - "CATEGORY" - top-level category only
 * - "CATEGORY.SUBTYPE" - category with subtype
 *
 * These utilities provide a consistent way to extract category keys, subtype keys,
 * and check relationships between categories across all classification stages.
 *
 * @module utils/category-utils
 */

/**
 * Parsed category name structure
 */
export interface ParsedCategoryName {
  /** Top-level category key (e.g., "FINANCE") */
  category: string;
  /** Subtype key if present (e.g., "BANKING"), null otherwise */
  subtype: string | null;
  /** Whether the category has a subtype */
  hasSubtype: boolean;
  /** Original full category name */
  fullName: string;
}

/**
 * Extract category key from full category name.
 * Handles both "CATEGORY" and "CATEGORY.SUBTYPE" formats.
 *
 * @param fullCategoryName Full category name (e.g., "FINANCE.BANKING")
 * @returns Category key (e.g., "FINANCE")
 *
 * @example
 * getCategoryKey("FINANCE") // "FINANCE"
 * getCategoryKey("FINANCE.BANKING") // "FINANCE"
 * getCategoryKey("FINANCE.BANKING.CHECKING") // "FINANCE"
 */
export function getCategoryKey(fullCategoryName: string): string {
  if (!fullCategoryName) {
    return '';
  }
  return fullCategoryName.split('.')[0];
}

/**
 * Extract subtype key from full category name.
 * Returns null if the category has no subtype.
 *
 * @param fullCategoryName Full category name (e.g., "FINANCE.BANKING")
 * @returns Subtype key (e.g., "BANKING") or null if no subtype
 *
 * @example
 * getSubtypeKey("FINANCE") // null
 * getSubtypeKey("FINANCE.BANKING") // "BANKING"
 * getSubtypeKey("FINANCE.BANKING.CHECKING") // "BANKING"
 */
export function getSubtypeKey(fullCategoryName: string): string | null {
  if (!fullCategoryName) {
    return null;
  }
  const parts = fullCategoryName.split('.');
  return parts.length > 1 ? parts[1] : null;
}

/**
 * Check if two categories are subtypes of the same parent category.
 * Both categories must have subtypes and share the same parent.
 *
 * @param category1 First full category name (e.g., "FINANCE.BANKING")
 * @param category2 Second full category name (e.g., "FINANCE.INVESTING")
 * @returns True if both are subtypes of the same parent category
 *
 * @example
 * areSubtypesOfSameCategory("FINANCE.BANKING", "FINANCE.INVESTING") // true
 * areSubtypesOfSameCategory("FINANCE.BANKING", "SHOPPING.ONLINE") // false
 * areSubtypesOfSameCategory("FINANCE", "FINANCE.BANKING") // false (first has no subtype)
 * areSubtypesOfSameCategory("FINANCE", "SHOPPING") // false (neither has subtype)
 */
export function areSubtypesOfSameCategory(category1: string, category2: string): boolean {
  // Both must have subtypes (contain dots)
  if (!category1.includes('.') || !category2.includes('.')) {
    return false;
  }

  // Extract parent categories
  const parent1 = getCategoryKey(category1);
  const parent2 = getCategoryKey(category2);

  // Parents must match
  return parent1 === parent2;
}

/**
 * Parse a full category name into its components.
 * Provides a structured view of category, subtype, and metadata.
 *
 * @param fullCategoryName Full category name to parse
 * @returns Parsed category name structure with all components
 *
 * @example
 * parseCategoryName("FINANCE")
 * // { category: "FINANCE", subtype: null, hasSubtype: false, fullName: "FINANCE" }
 *
 * parseCategoryName("FINANCE.BANKING")
 * // { category: "FINANCE", subtype: "BANKING", hasSubtype: true, fullName: "FINANCE.BANKING" }
 */
export function parseCategoryName(fullCategoryName: string): ParsedCategoryName {
  const category = getCategoryKey(fullCategoryName);
  const subtype = getSubtypeKey(fullCategoryName);

  return {
    category,
    subtype,
    hasSubtype: subtype !== null,
    fullName: fullCategoryName,
  };
}

